<?php require __DIR__.'/includes/auth.php'; $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ try{ if(!verify_csrf($_POST['csrf']??'')) throw new RuntimeException('Invalid CSRF token.'); if(!filter_var($_POST['email']??'',FILTER_VALIDATE_EMAIL)) throw new RuntimeException('Invalid email.'); if(($_POST['password']??'')!==($_POST['confirm_password']??'')) throw new RuntimeException('Passwords do not match.'); $avatar=upload_profile_image($_FILES['profile_image']??[]); $stmt=db()->prepare('INSERT INTO users(full_name,email,mobile,password_hash,profile_image,role,status) VALUES(?,?,?,?,?,"student","active")'); $stmt->execute([trim($_POST['full_name']),strtolower(trim($_POST['email'])),trim($_POST['mobile']),password_hash($_POST['password'],PASSWORD_DEFAULT),$avatar]); login_user($_POST['email'],$_POST['password']); redirect('/user/dashboard.php'); }catch(Throwable $e){ $error=$e->getMessage(); }} $title='Register'; require __DIR__.'/includes/header.php'; ?>
<section class="py-5"><div class="container"><div class="glass-card p-4 mx-auto" style="max-width:720px"><h1>Create Student Account</h1><?php if($error):?><div class="alert alert-danger"><?=e($error)?></div><?php endif;?><form method="post" enctype="multipart/form-data" class="row g-3"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><div class="col-md-6"><label>Full Name</label><input required name="full_name" class="form-control"></div><div class="col-md-6"><label>Email</label><input required type="email" name="email" class="form-control"></div><div class="col-md-6"><label>Mobile Number</label><input required name="mobile" class="form-control"></div><div class="col-md-6"><label>Profile Image</label><input type="file" name="profile_image" class="form-control" accept="image/*"></div><div class="col-md-6"><label>Password</label><input required type="password" name="password" class="form-control"></div><div class="col-md-6"><label>Confirm Password</label><input required type="password" name="confirm_password" class="form-control"></div><div class="col-12"><button class="btn btn-gradient w-100">Register</button></div></form></div></div></section><?php require __DIR__.'/includes/footer.php'; ?>
